  ('social-worker-moex-00633', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某醫務社會工作師想要檢驗家屬支持與病人心理狀態之關係，蒐集家屬陪同病人的時間，並以心 理適應量表測量病人適應程度，發現家屬陪同病人的時間越多，病人的住院適應程度越好。有關 概念與變項的敘述，下列何者正確？', '["病人的心理狀態為變項，病人的心理適應量表分數為概念", "病人的心理狀態為概念，病人的心理適應量表分數為變項", "家屬支持為變項，家屬陪同病人的時間為概念", "家屬支持為概念，家屬陪同病人的時間為概念"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00634', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '承上題，下列何者為此一研究的分析單位（unitsofanalysis）？', '["社會工作師", "病人家屬", "病人", "醫院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00635', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述何者不是假設？', '["每天所喝的咖啡量越多，則每天的睡眠時間越少", "不良的居住環境與酗酒量沒有相關", "享有社會福利是每一位國民之基本權利", "工作者之教育程度越高，其在工作上之滿意程度越低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00636', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於概念與變項之敘述，下列何者正確？', '["所有變項均為概念，反之亦然", "某些變項為概念，而所有概念均為變項", "所有變項均為概念，但概念不一定為變項", "概念通常可以直接測量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00637', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關實驗設計的內在效度與外在效度，下列何者正確？', '["實驗結果無法推論真實世界情況，外在效度低", "實驗結果無法推論真實世界情況，內在效度低", "實驗過程依變項是因其他因素所造成的程度，指具有內在效度", "實驗排除其他可能解釋依變項變動因素，指具有外在效度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00638', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於人類行為的解釋模式，下列敘述何者錯誤？', '["個殊模式（idiographicmodel）是探究人類主觀感受、經驗與歷程", "律則模式（nomotheticmodel）是找出人類行為普遍的因果關係", "個殊模式可了解個別服務對象的適用性", "律則模式無法提供社工服務的指引"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00639', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當自變項與依變項在時間順序上發生模稜兩可的情況，是指內在效度的那一種威脅？', '["測量工具改變", "時間歷程", "選擇性偏誤", "因果影響方向的不確定性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00640', 'social-worker', 'social-worker-moex-112-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於虛假關係（spuriousrelationship），下列敘述何者正確？', '["兩個沒有因果關係的變項成為曲線關係", "兩個有因果關係的變項，因為某干擾因素而導致統計學上的關係減弱", "兩個沒有因果關係的變項，因為某些干擾因素而出現統計學上的相關", "兩個有因果關係的變項，因為某干擾因素而出現統計學上的無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "029d7798da55", "answer_pdf_sha1": "8f2f2439a807", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
